# Extract all human messages from Claude conversations
python3 -c "
import json, glob, os

files = glob.glob(os.path.expanduser('~/.claude/projects/-home-mega/*.jsonl'))
messages = []
for f in files:
    with open(f) as fh:
        for line in fh:
            try:
                obj = json.loads(line)
                if obj.get('type') == 'user':
                    msg = obj.get('message', {})
                    if msg.get('role') == 'user':
                        content = msg.get('content', '')
                        if isinstance(content, list):
                            text = ' '.join(c.get('text','') for c in content if isinstance(c,dict) and c.get('type')=='text')
                        else:
                            text = str(content)
                        text = text.strip()
                        if text and len(text) > 10 and not text.startswith('{') and 'tool_result' not in text[:50]:
                            messages.append(text)
            except: pass

print(f'Total human messages: {len(messages)}')
print(f'Total characters: {sum(len(m) for m in messages):,}')
print()
print('--- SAMPLE (first 10) ---')
for m in messages[:10]:
    print(repr(m[:120]))
"

