   315→            continue;
   316→        }
   317→
   318→        // Pull neighbours via store search (semantic when enabled, keyword otherwise).
   319→        let neighbours = match state
   320→            .memory_store
   321→            .search(&seed.content, req.neighbour_k)
   322→            .await
   323→        {
   324→            Ok(entries) => entries
   325→                .into_iter()
   326→                .filter(|e| e.namespace == namespace)
   327→                .collect::<Vec<_>>(),
   328→            Err(e) => {
