   336→        let mut cluster_ids: Vec<String> = Vec::new();
   337→
   338→        for e in neighbours.into_iter().chain(std::iter::once(seed.clone())) {
   339→            let Some(id) = e.id.as_ref().map(|i| i.0.clone()) else {
   340→                continue;
   341→            };
   342→            if visited.insert(id.clone()) {
   343→                cluster_ids.push(id);
   344→                cluster.push(e);
   345→            }
   346→        }
   347→
   348→        if cluster.len() < req.min_cluster_size {
   349→            continue;
   350→        }
   351→
   352→        consolidated_clusters += 1;
   353→
   354→        // Build a simple summary. (Week 5+: LLM synthesis + archival metadata.)
   355→        cluster.sort_by(|a, b| {
   356→            b.importance
   357→                .partial_cmp(&a.importance)
   358→                .unwrap_or(std::cmp::Ordering::Equal)
   359→        });
   360→        let mut summary_lines: Vec<String> = Vec::new();
   361→        summary_lines.push(format!(
   362→            "Consolidated memory cluster ({} entries):",
   363→            cluster.len()
   364→        ));
   365→        for e in cluster.iter().take(24) {
   366→            summary_lines.push(format!(
   367→                "- {}",
   368→                truncate(&e.content.replace('\n', " "), 180)
   369→            ));
   370→        }
   371→
   372→        let new_importance = cluster.iter().map(|e| e.importance).fold(0.0_f64, f64::max);
   373→
   374→        let consolidated_entry = MemoryEntry {
   375→            id: None,
   376→            content: summary_lines.join("\n"),
   377→            source: "consolidation".to_string(),
   378→            importance: new_importance,
   379→            created_at: None,
   380→            namespace: namespace.clone(),
   381→            tags: vec![],
   382→            domain: Default::default(),
   383→            confidence: 1.0,
   384→            version: 1,
   385→            superseded_by: None,
   386→            key: None,
   387→            raw_artifact: None,
   388→            tier: None,
   389→        };
