   392→            Ok(MemoryWriteResult::Written(id))
   393→            | Ok(MemoryWriteResult::Contradiction { new_id: id, .. }) => id.0,
   394→            Err(e) => {
   395→                tracing::error!(error = %e, "memory consolidate write failed");
   396→                continue;
   397→            }
   398→        };
   399→        created.push(consolidated_id);
