   405→                    Ok(false) => {}
   406→                    Err(e) => tracing::warn!(error = %e, "memory consolidate delete failed"),
   407→                }
   408→            }
   409→        }
   410→    }
   411→
   412→    (
   413→        StatusCode::OK,
   414→        Json(json!({
   415→            "status": "ok",
   416→            "namespace": namespace,
   417→            "clusters": consolidated_clusters,
   418→            "created": created,
   419→            "deleted": deleted_count,
   420→            "delete_originals": req.delete_originals
