  padding: 2rem;
  border-radius: 1rem;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.statusCard:hover {
  transform: translateY(-8px);
  box-shadow: 0 15px 40px rgba(0, 0, 0, 0.3);
}

.statusCard h3 {
  font-size: 1.3rem;
  color: var(--sovereign-gold);
  margin-bottom: 1rem;
}

.statusCard p {
  color: #ccc;
  font-size: 1rem;
  margin-bottom: 0.7rem;
}

.statusCard p strong {
  color: var(--omega-cyan);
}

.error {
  color: #ff6b6b;
  font-weight: bold;
}

/* Provider badges */
.providerList {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-top: 0.5rem;
}

.providerBadge {
  padding: 0.2rem 0.6rem;
  border-radius: 0.3rem;
  font-size: 0.75rem;
  font-family: var(--font-mono);
  font-weight: 600;
  letter-spacing: 0.05em;
}

.providerOn {
  background: rgba(0, 255, 255, 0.12);
  border: 1px solid rgba(0, 255, 255, 0.35);
  color: var(--omega-cyan);
}

.providerOff {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  color: #555;
}

.dimText {
  color: #555;
  font-size: 0.85rem;
}

/* Chat section */
.chatSection {
  margin-top: 6rem;
  padding: 4rem 1.5rem;
  border-radius: 1.5rem;
  background: rgba(0, 0, 0, 0.1);
}

.chatForm {
  display: flex;
  gap: 1rem;
  align-items: flex-end;
}

.chatInput {
  flex: 1;
  padding: 0.9rem 1rem;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 0.6rem;
  color: var(--foreground);
  font-family: var(--font-sans);
  font-size: 1rem;
  resize: vertical;
  outline: none;
  transition: border-color 0.2s ease;
}

.chatInput:focus {
  border-color: var(--omega-cyan);
}

.memInput {
  flex: 1;
  padding: 0.9rem 1rem;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 0.6rem;
  color: var(--foreground);
  font-family: var(--font-sans);
  font-size: 1rem;
  outline: none;
  transition: border-color 0.2s ease;
}

.memInput:focus {
  border-color: var(--sovereign-gold);
}

.submitBtn {
  padding: 0.8rem 1.8rem;
  font-size: 1rem;
  font-weight: 600;
  color: #000;
  background: var(--omega-cyan);
  border: none;
  border-radius: 0.6rem;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.2s ease, transform 0.15s ease;
}

.submitBtn:hover:not(:disabled) {
  background: var(--sovereign-gold);
  transform: translateY(-1px);
}

.submitBtn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.chatResponse {
  margin-top: 1.5rem;
  padding: 1.5rem;
  border-radius: 0.8rem;
}

.chatMeta {
  display: flex;
  gap: 0.75rem;
  align-items: center;
  margin-bottom: 0.75rem;
}

.chatText {
  color: var(--foreground);
  line-height: 1.7;
  white-space: pre-wrap;
}

/* Memory section */
.memorySection {
  margin-top: 4rem;
  padding: 4rem 1.5rem;
  border-radius: 1.5rem;
  background: rgba(0, 0, 0, 0.1);
}

.memHits {
  margin-top: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.memHit {
  padding: 1.25rem 1.5rem;
  border-radius: 0.7rem;
}

.hitMeta {
  display: flex;
  gap: 0.6rem;
  align-items: center;
  margin-bottom: 0.6rem;
}

.memContent {
  color: #bbb;
  font-size: 0.9rem;
  line-height: 1.6;
  white-space: pre-wrap;
  max-height: 8rem;
  overflow: hidden;
  text-overflow: ellipsis;
}

.footer {
  padding: 6rem 2rem 4rem;
  text-align: center;
  color: #444;
  font-size: 0.9rem;
}

.footer p {
  margin-bottom: 0.5rem;
}

.mono {
  font-family: var(--font-mono);
  color: #222;
  text-transform: uppercase;
  letter-spacing: 0.3em;
}

